const rows = $input.all();

function getLookupValue(value) {
  if (Array.isArray(value)) return value[0];
  return value;
}

function getLookupText(value) {
  if (Array.isArray(value)) return value[0] || '';
  return value || '';
}

function clean(value) {
  return String(getLookupText(value) || '').trim();
}

function normalizeDate(value) {
  if (!value) return '';
  return String(getLookupValue(value) || '').slice(0, 10);
}

function nightsBetween(checkIn, checkOut) {
  if (!checkIn || !checkOut) return '';

  const start = new Date(`${checkIn}T00:00:00Z`);
  const end = new Date(`${checkOut}T00:00:00Z`);

  const diff = Math.round((end - start) / 86400000);
  return Number.isFinite(diff) && diff > 0 ? diff : '';
}

function normalizeBedId(roomId, bedIdRaw) {
  const room = String(roomId || '').trim().toUpperCase();
  const raw = String(bedIdRaw || '').trim();

  if (!raw) return '';

  if (/^R\d+-B\d+$/i.test(raw)) {
    return raw.toUpperCase();
  }

  const bedNumberMatch = raw.match(/bed\s*(\d+)/i);

  if (room && bedNumberMatch) {
    return `${room}-B${bedNumberMatch[1]}`;
  }

  const numberOnlyMatch = raw.match(/^(\d+)$/);

  if (room && numberOnlyMatch) {
    return `${room}-B${numberOnlyMatch[1]}`;
  }

  return raw;
}

function findFieldByExactNames(fields, names) {
  for (const name of names) {
    if (fields[name] !== undefined && fields[name] !== null && clean(fields[name]) !== '') {
      return clean(fields[name]);
    }
  }

  return '';
}

function findFieldByLooseMatch(fields, requiredWords, blockedWords = []) {
  const keys = Object.keys(fields || {});

  for (const key of keys) {
    const keyLower = key.toLowerCase();

    const hasAllRequired = requiredWords.every(word => keyLower.includes(word));
    const hasBlocked = blockedWords.some(word => keyLower.includes(word));

    if (!hasAllRequired || hasBlocked) {
      continue;
    }

    const value = clean(fields[key]);

    if (value) {
      return value;
    }
  }

  return '';
}

function getPaymentStatus(fields) {
  const exact = findFieldByExactNames(fields, [
    'Payment Status',
    'Payment status',
    'payment_status',
    'Booking Payment Status',
    'Booking payment status',
    'Payment Status Lookup',
    'Payment Status lookup',
    'Payment Status (from Booking)',
    'Payment status (from Booking)',
    'Payment Status (from Bookings)',
    'Payment status (from Bookings)',
    'Payment Status from Booking',
    'Payment',
    'Booking Payment'
  ]);

  if (exact) return exact;

  const loosePaymentStatus = findFieldByLooseMatch(fields, ['payment', 'status']);
  if (loosePaymentStatus) return loosePaymentStatus;

  return '';
}

function getPackage(fields) {
  const exact = findFieldByExactNames(fields, [
    'Package',
    'package',
    'Package Name',
    'Package name',
    'package_name',
    'Selected Package',
    'Selected package',
    'Booking Package',
    'Booking package',
    'Package Lookup',
    'Package lookup',
    'Package (from Booking)',
    'Package Name (from Booking)',
    'Package (from Bookings)',
    'Package Name (from Bookings)',
    'Package from Booking',
    'Booking Package (from Booking)'
  ]);

  if (exact) return exact;

  const loosePackage = findFieldByLooseMatch(fields, ['package']);
  if (loosePackage) return loosePackage;

  return '';
}

function getDepositPaid(fields) {
  const exact = findFieldByExactNames(fields, [
    'Deposit Paid',
    'Deposit paid',
    'deposit_paid',
    'Booking Deposit Paid',
    'Booking deposit paid',
    'Deposit Paid Lookup',
    'Deposit Paid lookup',
    'Deposit Paid (from Booking)',
    'Deposit paid (from Booking)',
    'Deposit Paid (from Bookings)',
    'Deposit paid (from Bookings)',
    'Deposit Paid from Booking',
    'Deposit Paid from Bookings'
  ]);

  if (exact) return exact;

  const looseDepositPaid = findFieldByLooseMatch(fields, ['deposit', 'paid']);
  if (looseDepositPaid) return looseDepositPaid;

  return '';
}

function colorTypeFromFields(fields) {
  const source = String(clean(fields['Booking Source'])).toLowerCase();
  const status = String(clean(fields['Status'])).toLowerCase();
  const paymentStatus = String(getPaymentStatus(fields)).toLowerCase();
  const assignmentStatus = String(clean(fields['Assignment Status'])).toLowerCase();

  if (status.includes('cancel') || status.includes('expired')) return 'cancelled';
  if (paymentStatus === 'failed') return 'conflict';
  if (assignmentStatus.includes('review') || status.includes('review')) return 'needs_review';
  if (source.includes('operator') || source.includes('manual')) return 'operator';

  if (paymentStatus === 'paid' || paymentStatus === 'deposit_paid') {
    return 'confirmed';
  }

  return 'hold';
}

function formatMoneyForDisplay(value) {
  const raw = String(value || '').trim();

  if (!raw) return '';

  if (/^[€$£]/.test(raw)) {
    return raw;
  }

  const numberValue = Number(raw.replace(/,/g, ''));

  if (Number.isFinite(numberValue)) {
    return `€${numberValue}`;
  }

  return raw;
}

function displayText(fields) {
  const guestName =
    clean(fields['Guest Name']) ||
    clean(fields['Booking Guest Name']) ||
    clean(fields['Name']) ||
    'Guest';

  const paymentStatus = getPaymentStatus(fields);
  const depositPaid = formatMoneyForDisplay(getDepositPaid(fields));
  const packageName = getPackage(fields);
  const source = clean(fields['Booking Source']);

  const sourceLabel =
    String(source || '').toLowerCase().includes('operator') ||
    String(source || '').toLowerCase().includes('manual')
      ? 'Manual'
      : 'Auto';

  const pieces = [guestName];

  if (paymentStatus) pieces.push(paymentStatus);
  if (depositPaid) pieces.push(depositPaid);
  if (packageName) pieces.push(packageName);

  pieces.push(sourceLabel);

  return pieces.join(' - ');
}

function getDebugMatchingFieldNames(fields) {
  const keys = Object.keys(fields || {});

  return keys
    .filter(key => {
      const lower = key.toLowerCase();
      return (
        lower.includes('payment') ||
        lower.includes('package') ||
        lower.includes('deposit') ||
        lower.includes('status')
      );
    })
    .join(', ');
}

const output = [];

for (const item of rows) {
  const fields = item.json.fields || item.json;

  const bookingRecordId = getLookupValue(fields['Booking']) || getLookupValue(fields['Bookings']) || '';
  const bookingId = clean(fields['Booking ID']) || '';
  const bookingSource = clean(fields['Booking Source']) || '';

  const guestName =
    clean(fields['Guest Name']) ||
    clean(fields['Booking Guest Name']) ||
    clean(fields['Name']) ||
    '';

  const guestCount = clean(fields['Guest Count']) || '';

  const checkIn = normalizeDate(
    getLookupValue(fields['Assignment Start Date']) ||
    getLookupValue(fields['Check In'])
  );

  const checkOut = normalizeDate(
    getLookupValue(fields['Assignment End Date']) ||
    getLookupValue(fields['Check Out'])
  );

  const roomId = clean(fields['Room ID']) || '';

  const bedIdRaw =
    clean(fields['Bed ID']) ||
    clean(fields['Bed Label']) ||
    '';

  const bedId = normalizeBedId(roomId, bedIdRaw);

  const requestedRoomType = clean(fields['Requested Room Type']) || '';
  const roomPreference = clean(fields['Room Preference']) || '';
  const guestGenderGroupType = clean(fields['Guest Gender / Group Type']) || '';

  const status = clean(fields['Status']) || '';
  const paymentStatus = getPaymentStatus(fields);
  const assignmentStatus = clean(fields['Assignment Status']) || '';
  const packageName = getPackage(fields);
  const depositPaid = getDepositPaid(fields);

  output.push({
    json: {
      'Booking Record ID': bookingRecordId,
      'Booking ID': bookingId,
      'Booking Source': bookingSource,
      'Guest Name': guestName,
      'Guest Count': guestCount,
      'Check In': checkIn,
      'Check Out': checkOut,
      'Night Count': nightsBetween(checkIn, checkOut),
      'Room ID': roomId,
      'Bed ID': bedId,
      'Requested Room Type': requestedRoomType,
      'Room Preference': roomPreference,
      'Guest Gender / Group Type': guestGenderGroupType,
      'Status': status,
      'Payment Status': paymentStatus,
      'Assignment Status': assignmentStatus,
      'Package': packageName,
      'Deposit Paid': depositPaid,
      'Display Text': displayText(fields),
      'Color Type': colorTypeFromFields(fields),
      'Last Synced At': new Date().toISOString(),
      'Notes': clean(fields['Assignment Notes']) || '',
      'Debug Matching Field Names': getDebugMatchingFieldNames(fields)
    }
  });
}

return output;

const spreadsheetId = '1eISph-eVZpylAEFVRS22hxRvWydBj07vz6G-vO7T_cc';

// Planning tab sheetId/gid
const planningSheetId = 1622542535;

// Planning layout.
// Google Sheets rows/columns are zero-based here.
// Row 4 has dates, column C is first date, row 5 is first bed row.
const DATE_HEADER_ROW_INDEX = 3;
const FIRST_DATE_COL_INDEX = 2;
const FIRST_BED_ROW_INDEX = 4;

// Width of date/booking cells in pixels.
const DATE_COLUMN_PIXEL_WIDTH = 105;

// Money display.
const MONEY_SYMBOL = '€';

const planningValues = $input.first().json.values || [];
const syncRows = $('Code - Prepare Bookings Sync Rows').all().map(item => item.json);

function columnToLetter(columnIndexZeroBased) {
  let column = columnIndexZeroBased + 1;
  let letter = '';

  while (column > 0) {
    const remainder = (column - 1) % 26;
    letter = String.fromCharCode(65 + remainder) + letter;
    column = Math.floor((column - 1) / 26);
  }

  return letter;
}

function normalizeDate(value) {
  if (value === undefined || value === null || value === '') return '';

  const raw = String(value).trim();

  if (/^\d{4}-\d{2}-\d{2}$/.test(raw)) return raw;

  const slashDate = raw.match(/^(\d{1,2})\/(\d{1,2})\/(\d{2,4})$/);

  if (slashDate) {
    const day = slashDate[1].padStart(2, '0');
    const month = slashDate[2].padStart(2, '0');
    let year = slashDate[3];

    if (year.length === 2) year = `20${year}`;

    return `${year}-${month}-${day}`;
  }

  const dashDate = raw.match(/^(\d{1,2})-(\d{1,2})-(\d{2,4})$/);

  if (dashDate) {
    const day = dashDate[1].padStart(2, '0');
    const month = dashDate[2].padStart(2, '0');
    let year = dashDate[3];

    if (year.length === 2) year = `20${year}`;

    return `${year}-${month}-${day}`;
  }

  if (/^\d+(\.\d+)?$/.test(raw)) {
    const serial = Number(raw);

    if (serial > 30000 && serial < 70000) {
      const excelEpoch = new Date(Date.UTC(1899, 11, 30));
      const date = new Date(excelEpoch.getTime() + serial * 86400000);
      return date.toISOString().slice(0, 10);
    }
  }

  const parsed = new Date(raw);

  if (!Number.isNaN(parsed.getTime())) {
    return parsed.toISOString().slice(0, 10);
  }

  return '';
}

function addDays(dateStr, days) {
  const date = new Date(`${dateStr}T00:00:00Z`);
  date.setUTCDate(date.getUTCDate() + days);
  return date.toISOString().slice(0, 10);
}

function dateRangeNights(checkIn, checkOut) {
  const dates = [];

  const start = normalizeDate(checkIn);
  const end = normalizeDate(checkOut);

  if (!start || !end) return dates;

  let current = start;
  let safety = 0;

  while (current < end && safety < 400) {
    dates.push(current);
    current = addDays(current, 1);
    safety++;
  }

  return dates;
}

function colorForRow(row) {
  const colorType = String(row['Color Type'] || '').toLowerCase().trim();
  const status = String(row['Status'] || '').toLowerCase().trim();
  const paymentStatus = String(row['Payment Status'] || '').toLowerCase().trim();
  const assignmentStatus = String(row['Assignment Status'] || '').toLowerCase().trim();

  if (
    colorType === 'cancelled' ||
    status.includes('cancel') ||
    status.includes('expired')
  ) {
    return { red: 0.85, green: 0.85, blue: 0.85 };
  }

  if (
    colorType === 'conflict' ||
    paymentStatus === 'failed' ||
    assignmentStatus.includes('conflict')
  ) {
    return { red: 0.957, green: 0.8, blue: 0.8 };
  }

  if (
    colorType === 'needs_review' ||
    assignmentStatus.includes('review') ||
    status.includes('review')
  ) {
    return { red: 0.918, green: 0.863, blue: 0.973 };
  }

  if (
    colorType === 'operator' ||
    status.includes('blocked') ||
    String(row['Booking Source'] || '').toLowerCase().includes('block')
  ) {
    return { red: 0.812, green: 0.886, blue: 0.953 };
  }

  // Paid = slightly darker green
  if (paymentStatus === 'paid') {
    return { red: 0.714, green: 0.843, blue: 0.659 };
  }

  // Deposit paid = light green
  if (paymentStatus === 'deposit_paid' || colorType === 'confirmed') {
    return { red: 0.851, green: 0.918, blue: 0.827 };
  }

  // Waiting / hold / pending = orange
  return { red: 0.988, green: 0.898, blue: 0.8 };
}

function getPackage(row) {
  return String(
    row['Package'] ||
    row['Package Name'] ||
    row['Selected Package'] ||
    row['Booking Package'] ||
    ''
  ).trim();
}

function getDepositPaid(row) {
  return String(
    row['Deposit Paid'] ||
    row['Deposit Paid (from Booking)'] ||
    row['Deposit Paid (from Bookings)'] ||
    ''
  ).trim();
}

function formatMoneyForDisplay(value) {
  const raw = String(value || '').trim();

  if (!raw) return '';

  if (/^[€$£]/.test(raw)) return raw;

  const numberValue = Number(raw.replace(/,/g, ''));

  if (Number.isFinite(numberValue)) {
    return `${MONEY_SYMBOL}${numberValue}`;
  }

  return raw;
}

function isManualBooking(row) {
  const source = String(row['Booking Source'] || '').toLowerCase();
  const notes = String(row['Notes'] || '').toLowerCase();
  const bookingId = String(row['Booking ID'] || '').toLowerCase();

  return (
    source.includes('operator') ||
    source.includes('manual') ||
    notes.includes('manual entry id') ||
    bookingId.startsWith('man-')
  );
}

function makeDisplayText(row) {
  const guestName = String(
    row['Guest Name'] ||
    row['Booking Guest Name'] ||
    row['Name'] ||
    'Guest'
  ).trim();

  const paymentStatus = String(row['Payment Status'] || '').trim();
  const depositPaid = formatMoneyForDisplay(getDepositPaid(row));
  const packageName = getPackage(row);
  const sourceLabel = isManualBooking(row) ? 'Manual' : 'Auto';

  const pieces = [guestName];

  if (paymentStatus) pieces.push(paymentStatus);
  if (depositPaid) pieces.push(depositPaid);
  if (packageName) pieces.push(packageName);

  pieces.push(sourceLabel);

  return pieces.join(' - ');
}

function makeNote(row) {
  const parts = [
    row['Booking ID'] ? `Booking ID: ${row['Booking ID']}` : '',
    row['Booking Record ID'] ? `Record: ${row['Booking Record ID']}` : '',
    row['Guest Name'] ? `Guest: ${row['Guest Name']}` : '',
    getPackage(row) ? `Package: ${getPackage(row)}` : '',
    getDepositPaid(row) ? `Deposit Paid: ${formatMoneyForDisplay(getDepositPaid(row))}` : '',
    row['Check In'] && row['Check Out'] ? `Dates: ${row['Check In']} to ${row['Check Out']}` : '',
    row['Bed ID'] ? `Bed: ${row['Bed ID']}` : '',
    row['Room ID'] ? `Room: ${row['Room ID']}` : '',
    row['Room Preference'] ? `Room preference: ${row['Room Preference']}` : '',
    row['Requested Room Type'] ? `Room type: ${row['Requested Room Type']}` : '',
    row['Guest Gender / Group Type'] ? `Gender/group: ${row['Guest Gender / Group Type']}` : '',
    row['Status'] ? `Status: ${row['Status']}` : '',
    row['Payment Status'] ? `Payment Status: ${row['Payment Status']}` : '',
    row['Assignment Status'] ? `Assignment: ${row['Assignment Status']}` : '',
    row['Booking Source'] ? `Source: ${row['Booking Source']}` : '',
    row['Notes'] ? `Notes: ${row['Notes']}` : ''
  ].filter(Boolean);

  return parts.join('\n');
}

function makeBookingGroupKey(row) {
  return String(
    row['Booking Record ID'] ||
    row['Booking ID'] ||
    `${row['Guest Name'] || 'Guest'}-${row['Check In'] || ''}-${row['Check Out'] || ''}`
  ).trim();
}

function makeBorderRequest(startRowIndex, endRowIndex, startColumnIndex, endColumnIndex) {
  const border = {
    style: 'SOLID_MEDIUM',
    width: 2,
    color: { red: 0, green: 0, blue: 0 }
  };

  return {
    updateBorders: {
      range: {
        sheetId: planningSheetId,
        startRowIndex,
        endRowIndex,
        startColumnIndex,
        endColumnIndex
      },
      top: border,
      bottom: border,
      left: border,
      right: border
    }
  };
}

const dateHeaderRow = planningValues[DATE_HEADER_ROW_INDEX] || [];
const dateToColIndex = {};

for (let col = FIRST_DATE_COL_INDEX; col < dateHeaderRow.length; col++) {
  const normalized = normalizeDate(dateHeaderRow[col]);

  if (normalized) {
    dateToColIndex[normalized] = col;
  }
}

const bedIdToRowIndex = {};
let maxBedRowIndex = FIRST_BED_ROW_INDEX;

for (let row = FIRST_BED_ROW_INDEX; row < planningValues.length; row++) {
  const bedId = String((planningValues[row] || [])[0] || '').trim();

  if (/^R\d+-B\d+$/i.test(bedId)) {
    bedIdToRowIndex[bedId.toUpperCase()] = row;
    maxBedRowIndex = Math.max(maxBedRowIndex, row);
  }
}

const dateColumns = Object.values(dateToColIndex);
const maxDateColIndex = dateColumns.length ? Math.max(...dateColumns) : 60;

const requests = [];
const warnings = [];
const bookingGroups = {};

requests.push({
  updateDimensionProperties: {
    range: {
      sheetId: planningSheetId,
      dimension: 'COLUMNS',
      startIndex: FIRST_DATE_COL_INDEX,
      endIndex: maxDateColIndex + 1
    },
    properties: {
      pixelSize: DATE_COLUMN_PIXEL_WIDTH
    },
    fields: 'pixelSize'
  }
});

requests.push({
  repeatCell: {
    range: {
      sheetId: planningSheetId,
      startRowIndex: FIRST_BED_ROW_INDEX,
      endRowIndex: maxBedRowIndex + 1,
      startColumnIndex: FIRST_DATE_COL_INDEX,
      endColumnIndex: maxDateColIndex + 1
    },
    cell: {
      userEnteredFormat: {
        backgroundColor: { red: 1, green: 1, blue: 1 },
        textFormat: {
          bold: false,
          fontSize: 9,
          foregroundColor: { red: 0, green: 0, blue: 0 }
        },
        wrapStrategy: 'WRAP',
        horizontalAlignment: 'CENTER',
        verticalAlignment: 'MIDDLE'
      },
      note: ''
    },
    fields: 'userEnteredValue,note,userEnteredFormat.backgroundColor,userEnteredFormat.textFormat,userEnteredFormat.wrapStrategy,userEnteredFormat.horizontalAlignment,userEnteredFormat.verticalAlignment'
  }
});

requests.push({
  updateBorders: {
    range: {
      sheetId: planningSheetId,
      startRowIndex: FIRST_BED_ROW_INDEX,
      endRowIndex: maxBedRowIndex + 1,
      startColumnIndex: FIRST_DATE_COL_INDEX,
      endColumnIndex: maxDateColIndex + 1
    },
    top: { style: 'NONE' },
    bottom: { style: 'NONE' },
    left: { style: 'NONE' },
    right: { style: 'NONE' },
    innerHorizontal: { style: 'NONE' },
    innerVertical: { style: 'NONE' }
  }
});

for (const row of syncRows) {
  const bedId = String(row['Bed ID'] || '').trim().toUpperCase();
  const checkIn = normalizeDate(row['Check In']);
  const checkOut = normalizeDate(row['Check Out']);
  const displayText = makeDisplayText(row);
  const color = colorForRow(row);
  const note = makeNote(row);

  if (!bedId || !checkIn || !checkOut) {
    warnings.push(`Skipped row missing bed/date: ${row['Booking ID'] || JSON.stringify(row)}`);
    continue;
  }

  const rowIndex = bedIdToRowIndex[bedId];

  if (rowIndex === undefined) {
    warnings.push(`Skipped ${row['Booking ID'] || ''}: bed ${bedId} not found on Planning tab`);
    continue;
  }

  const stayDates = dateRangeNights(checkIn, checkOut);

  if (!stayDates.length) {
    warnings.push(`Skipped ${row['Booking ID'] || ''}: no stay dates from ${checkIn} to ${checkOut}`);
    continue;
  }

  const bookingGroupKey = makeBookingGroupKey(row);

  if (!bookingGroups[bookingGroupKey]) {
    bookingGroups[bookingGroupKey] = {
      minRow: rowIndex,
      maxRow: rowIndex,
      minCol: null,
      maxCol: null
    };
  }

  for (let index = 0; index < stayDates.length; index++) {
    const dateStr = stayDates[index];
    const colIndex = dateToColIndex[dateStr];

    if (colIndex === undefined) {
      warnings.push(`Skipped ${row['Booking ID'] || ''}: date ${dateStr} not found on Planning tab`);
      continue;
    }

    const isFirstCell = index === 0;

    bookingGroups[bookingGroupKey].minRow = Math.min(bookingGroups[bookingGroupKey].minRow, rowIndex);
    bookingGroups[bookingGroupKey].maxRow = Math.max(bookingGroups[bookingGroupKey].maxRow, rowIndex);
    bookingGroups[bookingGroupKey].minCol =
      bookingGroups[bookingGroupKey].minCol === null
        ? colIndex
        : Math.min(bookingGroups[bookingGroupKey].minCol, colIndex);
    bookingGroups[bookingGroupKey].maxCol =
      bookingGroups[bookingGroupKey].maxCol === null
        ? colIndex
        : Math.max(bookingGroups[bookingGroupKey].maxCol, colIndex);

    requests.push({
      updateCells: {
        start: {
          sheetId: planningSheetId,
          rowIndex,
          columnIndex: colIndex
        },
        rows: [
          {
            values: [
              {
                userEnteredValue: {
                  stringValue: isFirstCell ? displayText : ''
                },
                note,
                userEnteredFormat: {
                  backgroundColor: color,
                  wrapStrategy: 'WRAP',
                  textFormat: {
                    bold: isFirstCell,
                    fontSize: 9,
                    foregroundColor: { red: 0, green: 0, blue: 0 }
                  },
                  horizontalAlignment: 'CENTER',
                  verticalAlignment: 'MIDDLE'
                }
              }
            ]
          }
        ],
        fields: 'userEnteredValue,note,userEnteredFormat.backgroundColor,userEnteredFormat.wrapStrategy,userEnteredFormat.textFormat,userEnteredFormat.horizontalAlignment,userEnteredFormat.verticalAlignment'
      }
    });
  }
}

for (const group of Object.values(bookingGroups)) {
  if (
    group.minRow !== null &&
    group.maxRow !== null &&
    group.minCol !== null &&
    group.maxCol !== null
  ) {
    requests.push(
      makeBorderRequest(
        group.minRow,
        group.maxRow + 1,
        group.minCol,
        group.maxCol + 1
      )
    );
  }
}

const dateMapSample = Object.entries(dateToColIndex)
  .slice(0, 20)
  .map(([date, col]) => `${date}:${columnToLetter(col)}`);

const bedMapSample = Object.entries(bedIdToRowIndex)
  .slice(0, 20)
  .map(([bed, row]) => `${bed}:row${row + 1}`);

return [
  {
    json: {
      spreadsheetId,
      planning_sheet_id: planningSheetId,
      request_count: requests.length,
      painted_booking_rows: syncRows.length,
      date_column_pixel_width: DATE_COLUMN_PIXEL_WIDTH,
      date_header_sample: dateHeaderRow.slice(0, 30),
      date_map_sample: dateMapSample,
      bed_map_sample: bedMapSample,
      warnings,
      requests
    }
  }
];

return [
  {
    json: {
      run_paint: true,
      timestamp: new Date().toISOString()
    }
  }
];
